#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int i;
        for (i = 0; i < n; i++) {
            if (s[i] == s[(i + 1) % n]) {
                break;
            }
        }
        if (i == n) {
            printf("yes\n");
            continue;
        }
        for (i = 0; i < n; i++) {
            if (s[i] == s[(i + n / 2) % n]) {
                break;
            }
        }
        if (i == n) {
            printf("yes\n");
            continue;
        }
        printf("no\n");
    }
    return 0;
}

